using System.ComponentModel.DataAnnotations;
using Microsoft.AspNetCore.Identity;

namespace WebApplication.Data.Models;

/// <summary>
/// User entity.
/// </summary>
public class ApplicationUser : IdentityUser
{
    /// <summary>
    /// Access token for the API calls from Worker.
    /// Will be autogenerated.
    /// </summary>
    [MaxLength(16)]
    public string? AccessToken { get; set; }
    
    /// <summary>
    /// User role for application security.
    /// Admin has to verify account.
    /// </summary>
    public UserRole Role { get; set; } = UserRole.NotVerified;
    
    /// <summary>
    /// All engines, that user has.
    /// </summary>
    [Required]
    public List<Engine> Engines { get; set; } = [];
    
    /// <summary>
    /// All worker logs of the user.
    /// </summary>
    [Required]
    public List<WorkerLog> WorkerLogs { get; set; } = [];
    
    /// <summary>
    /// All tests of the user.
    /// </summary>
    [Required]
    public required List<Test> Tests { get; set; } = [];
    
    /// <summary>
    /// Opening books, that user added.
    /// </summary>
    public required List<OpeningBook> OpeningBooks { get; set; } = [];
}